: false, "strong_id__": "17857860852484788", "content_type": "comment", "share_enabled": false, "created_at_utc": 1756416603, "text_translation": "✨❤️ Affirmations to repair emotional relationships ❤️✨\n\nI deserve a relationship full of love and respect 🕊️\nI attract harmony and serenity between myself and those I love 💫\nI allow forgiveness to fill my heart and open doors to return 💕\nI’m sending pure love energy reaching his heart right now 🌹\nI deserve to repair every relationship that God has destined to continue ✨\nI receive his return to me with love, peace and contentment 🌈\n\n🧿 Write in the comments: “Fix my relationship” to activate the intention of repair and attract return 💫", "is_ranked_comment": false, "did_report_as_spam": false, "private_reply_status": 0}, "taken_at": 1756416600, "can_reply": false, "has_audio": true, "has_liked": false, "like_count": 668, "media_type": 2, "play_count": 9459, "display_uri": "https://instagram.fnjf7-2.fna.fbcdn.net/v/t51.2885-15/539941842_4167917286812894_6242766187387344022_n.jpg?stp=c0.248.640.640a_dst-jpg_e15_tt6&_nc_ht=instagram.fnjf7-2.fna.fbcdn.net&_nc_cat=102&_nc_oc=Q6cZ2QHPyxYiN1npbn-4vZJbyMc306iWFXRdRSfQzS3NlkRz_XBDhXfUAWSgDRyR0X6Jy-g&_nc_ohc=AP6amh2_AwAQ7kNvwGHMmUK&_nc_gid=HUM0KbfkbDvDSLDak-Im8A&edm=ACaJ6XgBAAAA&ccb=7-5&oh=00_AfZZ2p1i5Uc5qjEHX2WWH1S8hom69CsAbuFFxw6Zgx1QuA&oe=68D482C8&_nc_sid=594fa5", "filter_type": 0, "mezql_token": "0:iVPzp1heQomxJ+EJkjRoZw==", "strong_id__": "3709413649401021726_46364740824", "fb_user_tags": {"in": []}, "photo_of_you": false, "product_type": "clips", "comment_count": 454, "ig_play_count": 9459, "igbio_product": null, "is_quiet_post": false, "clips_metadata": {"nux_info": null, "show_tips": null, "audio_type": "licensed_music", "music_info": {"music_asset_info": {"id": "9583527475040311", "title": "My Heart Will Go On (Love Theme from \"Titanic\")", "lyrics": null, "subtitle": "", "artist_id": "262382622000272", "has_lyrics": true, "ig_username": "celinedion", "is_explicit"