Q6cZ2QG4jekY914ozAKWRA0fBnvGLziuPRlgyx0QxmYeEJVAsxNb0NQH8NAr91WZhx0hu4g&_nc_ohc=6qHr9mutyjcQ7kNvwFfotRI&_nc_gid=Yev-2d9GmY1ZUYpz_iCyQw&edm=APU89FABAAAA&ccb=7-5&oh=00_AfbX-yo-VWL7HvVqny1iKf-5p5gwI33A4ogBBQIS0rZIow&oe=68D4A7D4&_nc_sid=bc0c2c", "config_width": 320, "config_height": 320}, {"src": "https://scontent-lhr6-2.cdninstagram.com/v/t51.2885-15/551054337_1134200744802804_6576893992573147133_n.jpg?stp=c0.248.640.640a_dst-jpg_e15_s480x480_tt6&efg=eyJ2ZW5jb2RlX3RhZyI6ImltYWdlX3VybGdlbi42NDB4MTEzNi5zZHIuZjcxODc4Lm5mcmFtZV9jb3Zlcl9mcmFtZS5jMiJ9&_nc_ht=scontent-lhr6-2.cdninstagram.com&_nc_cat=100&_nc_oc=Q6cZ2QG4jekY914ozAKWRA0fBnvGLziuPRlgyx0QxmYeEJVAsxNb0NQH8NAr91WZhx0hu4g&_nc_ohc=6qHr9mutyjcQ7kNvwFfotRI&_nc_gid=Yev-2d9GmY1ZUYpz_iCyQw&edm=APU89FABAAAA&ccb=7-5&oh=00_AfYKVtSdnfcWsHBLqzEMZo-ddmkkWe7svKRuufYUMiEWOg&oe=68D4A7D4&_nc_sid=bc0c2c", "config_width": 480, "config_height": 480}, {"src": "https://scontent-lhr6-2.cdninstagram.com/v/t51.2885-15/551054337_1134200744802804_6576893992573147133_n.jpg?stp=c0.248.640.640a_dst-jpg_e15_tt6&efg=eyJ2ZW5jb2RlX3RhZyI6ImltYWdlX3VybGdlbi42NDB4MTEzNi5zZHIuZjcxODc4Lm5mcmFtZV9jb3Zlcl9mcmFtZS5jMiJ9&_nc_ht=scontent-lhr6-2.cdninstagram.com&_nc_cat=100&_nc_oc=Q6cZ2QG4jekY914ozAKWRA0fBnvGLziuPRlgyx0QxmYeEJVAsxNb0NQH8NAr91WZhx0hu4g&_nc_ohc=6qHr9mutyjcQ7kNvwFfotRI&_nc_gid=Yev-2d9GmY1ZUYpz_iCyQw&edm=APU89FABAAAA&ccb=7-5&oh=00_AfaYZpadJ291_zjDytEG1MX0OeEwnNoQehCW1zRzbymHAg&oe=68D4A7D4&_nc_sid=bc0c2c", "config_width": 640, "config_height": 640}], "edge_media_to_caption": {"edges": [{"node": {"text": "O @gilbert_burns me chamou para uma live e o tema foi: Nutrição no MMA e Corte de peso. \n\nO corte de peso exige planejamento e individualização. Nesse trecho da live falamos um pouco sobre a tecnica Waterloading, uma tecnica validada na literatura como segura e eficiente para auxiliar na perda de peso. Nessa estrategia o atleta aumenta a ingestão de água dias antes da pesagem, em uma quantidade específica e, no dia do corte, reduz esse volume de forma controlada.\n\nFalamos tambem sobre a importância de continuar ingerindo água e alimentos mesmo no dia do corte de peso, afinal, sem energia, o corpo ativa mecanismos de defesa, retem líquidos e o corte fica muito mais difícil, por isso a alimentação e hidratação nesse dia tem grande importância, feita da forma e quantidades certas pra cada atleta."}}]}, "edge_media_to_comment": {"count": 65, "page_info": {"end_cursor": "", "has_next_page": true}}, "sharing_friction_info": {"bloks_app_url": null, "should_have_sharing_friction": false}, "fact_check_information": null, "viewer_in_photo_of_you": false, "edge_media_preview_like": {"count": 1481, "edges": []}, "edge_media_to_tagged_user": {"edges": [{"node": {"x": 0, "y": 0, "user": {"id": "22311116", "username": "gilbert_burns", "full_name": "GILBERT BURNS \"DURINHO\" 🇧🇷", "is_verified": true, "profile_pic_url": "https://scontent-lhr8-2.cdninstagram.com/v/t51.2885-19/516297306_18516565198039117_6994273045607875398_n.jpg?stp=dst-jpg_s150x150_tt6&efg=eyJ2ZW5jb2RlX3RhZyI6InByb2ZpbGVfcGljLmRqYW5nby4xMDgwLmMyIn0&_nc_ht=scontent-lhr8-2.cdninstagram.com&_nc_cat=101&_nc_oc=Q6cZ2QG4jekY914ozAKWRA0fBnvGLziuPRlgyx0QxmYeEJVAsxNb0NQH8NAr91WZhx0hu4g&_nc_ohc=Hi6RVbugOWkQ7kNvwEqvzGm&_nc_gid=Yev-2d9GmY1ZUYpz_iCyQw&edm=APU89FABAAAA&ccb=7-5&oh=00_AfYtcWiByetnsoN3GqPZlZuuvsuPbhuXrDuayoB7-1121g&oe=68D4AF22&_nc_sid=bc0c2c", "followed_by_viewer": false}}}]}, "fact_check_overall_rating": null, "sensitivity_friction_info": null, "edge_media_to_sponsor_user": {"edges": []}, "like_and_view_counts_disabled": false, "viewer_has_saved_to_collection": false}}, {"node": {"id": "3724444999372101660", "owner": {"id": "6878464298", "username": "gilbertburns_clips"}, "is_video": true, "location": null, "dash_info": {"is_dash_eligible": true, "number_of_qualities": 8, "video_dash_manifest": "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<MPD xmlns=\"urn:mpeg:dash:schema:mpd:2011\" xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\" xsi:schemaLocat